#include <vector>
#include <string>
#include <iostream>

using namespace std;

/**
 * @brief Solves the event processing task.
 * 
 * Processes an array of events sequentially, updating a score and a counter.
 * The processing stops if all events are processed or if the counter reaches 10.
 * 
 * @param events A vector of strings representing the events.
 * @return vector<long long> An array containing [score, counter].
 */
vector<long long> solve(vector<string> events) {
    long long score = 0;
    long long counter = 0;
    int n = events.size();

    for (int i = 0; i < n; ++i) {
        if (counter >= 10) {
            break; // Stop if counter reaches 10
        }

        const string& event = events[i];

        if (event == "0" || event == "1" || event == "2" || event == "3" || event == "4" || event == "6") {
            // Add the value to total score
            int value = 0;
            if (event == "0") value = 0;
            else if (event == "1") value = 1;
            else if (event == "2") value = 2;
            else if (event == "3") value = 3;
            else if (event == "4") value = 4;
            else if (event == "6") value = 6;

            score += value;
        } else if (event == "W") {
            // Counter increases by 1, no score change
            counter++;
        } else if (event == "WD") {
            // Total score increases by 1
            score += 1;
        } else if (event == "NB") {
            // Total score increases by 1
            score += 1;
        }
    }

    return {score, counter};
}
